# frozen_string_literal: true

require "hanami/router/errors"
require "mustermann/error"
require_relative "prefix"

module Hanami
  class Router
    # @api private
    class UrlHelpers
      # @since 2.0.0
      # @api private
      def initialize(base_url)
        @base_url = URI(base_url)
        @named = {}
        prefix = @base_url.path
        prefix = DEFAULT_PREFIX if prefix.empty?
        @prefix = Prefix.new(prefix)
      end

      # @api private
      def add(name, segment)
        @named[name] = segment
      end

      # @api private
      def path(name, variables = {})
        scalar_vars = variables.reject { |_, value| value.is_a?(Array) }
        array_vars = array_query_vars(variables)

        expanded_path = @named
          .fetch(name.to_sym) { raise MissingRouteError.new(name) }
          .expand(:append, scalar_vars)

        return expanded_path if array_vars.empty?

        join_char = expanded_path.include?("?") ? "&" : "?"
        "#{expanded_path}#{join_char}#{Rack::Utils.build_query(array_vars)}"
      rescue Mustermann::ExpandError => exception
        raise InvalidRouteExpansionError.new(name, exception.message)
      end

      # @api private
      def url(name, variables = {})
        @base_url + @prefix.join(path(name, variables)).to_s
      end

      private

      def array_query_vars(variables = {})
        variables
          .select { |_, value| value.is_a?(Array) }
          .to_h { |key, value| ["#{key}[]", value] }
      end
    end
  end
end

# frozen_string_literal: true
require "graphql/dataloader/source"

module GraphQL
  class Dataloader
    class ActiveRecordSource < GraphQL::Dataloader::Source
      def initialize(model_class, find_by: model_class.primary_key)
        @model_class = model_class
        @find_by = find_by
        @find_by_many = find_by.is_a?(Array)
        if @find_by_many
          @type_for_column = @find_by.map { |fb| @model_class.type_for_attribute(fb) }
        else
          @type_for_column = @model_class.type_for_attribute(@find_by)
        end
      end

      def result_key_for(requested_key)
        normalize_fetch_key(requested_key)
      end

      def normalize_fetch_key(requested_key)
        if @find_by_many
          requested_key.each_with_index.map do |k, idx|
            @type_for_column[idx].cast(k)
          end
        else
          @type_for_column.cast(requested_key)
        end
      end

      def fetch(record_ids)
        records = @model_class.where(@find_by => record_ids)
        record_lookup = {}
        if @find_by_many
          records.each do |r|
            key = @find_by.map { |fb| r.public_send(fb) }
            record_lookup[key] = r
          end
        else
          records.each { |r| record_lookup[r.public_send(@find_by)] = r }
        end
        record_ids.map { |id| record_lookup[id] }
      end
    end
  end
end
